from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

class BankAccount(BaseModel):
    account_number: float
    balance: float

class TransferRequest(BaseModel):
    sender_account: float
    receiver_account: float
    transfer_amount: float

class BankTransferResponse(BaseModel):
    status_message: str

# Sample in-memory data store for demonstration purposes
bank_accounts = {
    12345: 1000.0,
    67890: 500.0
}

@app.post("/transfer", response_model=BankTransferResponse)
async def bank_transfer(transfer_request: TransferRequest):
    # Input validation
    if transfer_request.transfer_amount <= 0:
        raise HTTPException(status_code=400, detail="Transfer amount must be greater than zero")

    # Check if sender and receiver accounts exist
    if transfer_request.sender_account not in bank_accounts:
        raise HTTPException(status_code=404, detail="Sender account not found")
    if transfer_request.receiver_account not in bank_accounts:
        raise HTTPException(status_code=404, detail="Receiver account not found")

    # Check if sender has sufficient balance
    sender_balance = bank_accounts[transfer_request.sender_account]
    if sender_balance < transfer_request.transfer_amount:
        return {"status_message": "FAILED: Insufficient funds"}

    # Process the transfer
    bank_accounts[transfer_request.sender_account] -= transfer_request.transfer_amount
    bank_accounts[transfer_request.receiver_account] += transfer_request.transfer_amount

    return {"status_message": "SUCCESS: Transfer completed"}
